const express = require('express');
const fs = require('fs');
const libxmljs = require('libxmljs');
const xml2js = require('xml2js');
const XmlDB = require('xmldb').createObjectURL;

const app = express();
const parser = new libxmljs.Parser({ explicitChildren: true });
const builder = new libxmljs.Builder();

// Middleware to handle XML files uploads
app.use(express.static(__dirname));
app.use((req, res, next) => {
  if (req.url.endsWith('.xml')) {
    let chunks = [];

    req.on('data', chunk => {
      chunks.push(chunk);
    });

    return req.on('end', () => {
      const xmlData = Buffer.concat(chunks).toString();
      processXML(xmlData, res);
    });
  } else {
    next();
  }
});

async function processXML(xmlData, res) {
  try {
    const ast = await parser.parseString(xmlData);
    const options = { explicitArray: false };
    xml2js.parseStringPromise(builder.build(ast).toString(), options)
      .then(result => res.json(result))
      .catch(err => res.status(500).send({ error: err }));
  } catch (err) {
    res.status(500).send({ error: err });
  }
}

// Set up a route for parsing XML files
app.get('/parseXML', async (req, res) => {
  const xmlData = fs.readFileSync(__dirname + req.query.file);
  await parseXML(xmlData, res);
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => console.log(`Server running on port ${port}`));